    .{ 
        .veins = 3,
        .size = 10,
        .height = 500,
        .minHeight = 0,
        .density = 0.125
    },
    .{ 
        .veins = 5,
        .size = 15,
        .height = 0,
        .minHeight = -500,
        .density = 0.25,
    },
    .{ 
        .veins = 8,
        .size = 20,
        .height = -500,
        .minHeight = -1000
        .density = 0.33,
    },
    .{ 
        .veins = 5,
        .size = 15,
        .height = -1000,
        .density = 0.10,
    }
}
